#include <stdio.h>
#include <stdint.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; unsigned int A, B;
        scanf("%d %u %u", &N, &A, &B);
        int a = __builtin_popcount(A);
        int b = __builtin_popcount(B);
        int c = a + b - N;
        if (c < 0) c = 0;
        int k = a + b - 2 * c;
        long long ans = 0;
        if (k > 0) {
            long long all = 1LL << N;               // 2^N
            long long low = 1LL << (N - k);          // 2^{N-k}
            ans = all - low;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

